@using sv_092670d577f14d7eb52b8573ba448c3b.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h2 class="mb-4">Job Application</h2>

    @if (!_submitted)
    {
        <!-- Step Indicator -->
        <nav class="mb-4">
            <ol class="step-indicator d-flex list-unstyled justify-content-between">
                @for (int i = 0; i < _stepLabels.Length; i++)
                {
                    var stepIndex = i;
                    var isCurrent = stepIndex == _currentStep;
                    var isCompleted = stepIndex < _currentStep;
                    var css = isCurrent ? "step active" : isCompleted ? "step completed" : "step";

                    <li class="@css text-center flex-fill position-relative">
                        @if (isCompleted)
                        {
                            <button type="button" class="btn btn-link p-0 text-decoration-none" @onclick="() => GoToStep(stepIndex)">
                                <span class="step-circle bg-success text-white">✓</span>
                                <span class="d-block small mt-1 text-success fw-semibold">@_stepLabels[stepIndex]</span>
                            </button>
                        }
                        else
                        {
                            <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white")">@(stepIndex + 1)</span>
                            <span class="d-block small mt-1 @(isCurrent ? "fw-semibold" : "text-muted")">@_stepLabels[stepIndex]</span>
                        }
                    </li>
                }
            </ol>
        </nav>

        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="alert alert-danger">@_errorMessage</div>
        }

        <!-- Step Content -->
        @switch (_currentStep)
        {
            case 0:
                <sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.ApplySteps.PersonalInfoStep
                    FullName="@_fullName" FullNameChanged="v => _fullName = v"
                    Email="@_email" EmailChanged="v => _email = v"
                    Phone="@_phone" PhoneChanged="v => _phone = v"
                    Address="@_address" AddressChanged="v => _address = v" />
                <div class="d-flex justify-content-end mt-3">
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_processing">
                        @if (_processing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Next
                    </button>
                </div>
                break;

            case 1:
                <sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.ApplySteps.WorkHistoryStep
                    Entries="_workEntries"
                    CurrentFlags="_currentJobFlags" />
                <div class="d-flex justify-content-between mt-3">
                    <button class="btn btn-outline-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 2:
                <sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.ApplySteps.ReferencesStep References="_references" />
                <div class="d-flex justify-content-between mt-3">
                    <button class="btn btn-outline-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 3:
                <sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.ApplySteps.CoverLetterStep
                    CoverLetter="@_coverLetter"
                    CoverLetterChanged="v => _coverLetter = v"
                    MaxLength="2000" />
                <div class="d-flex justify-content-between mt-3">
                    <button class="btn btn-outline-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 4:
                <sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.ApplySteps.ReviewStep
                    FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                    WorkEntries="_workEntries" CurrentFlags="_currentJobFlags"
                    References="_references"
                    CoverLetter="@_coverLetter"
                    OnEditSection="GoToStep" />
                <div class="d-flex justify-content-between mt-3">
                    <button class="btn btn-outline-secondary" @onclick="PrevStep" disabled="@_processing">Back</button>
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_processing">
                        @if (_processing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Submit Application
                    </button>
                </div>
                break;
        }
    }
    else
    {
        <!-- Confirmation -->
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="display-1 text-success">✓</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p>Application ID: <strong>@_applicationId</strong></p>
        </div>
    }
</div>

<style>
    .step-indicator {
        counter-reset: step;
    }
    .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 2rem;
        height: 2rem;
        border-radius: 50%;
        font-size: 0.85rem;
        font-weight: 600;
    }
    .step.completed .step-circle {
        cursor: pointer;
    }
    .step + .step::before {
        content: '';
        position: absolute;
        top: 1rem;
        left: -50%;
        width: 100%;
        height: 2px;
        background: #dee2e6;
        z-index: -1;
    }
    .step.completed + .step::before,
    .step.active + .step::before {
        background: #198754;
    }
</style>

@code {
    private static readonly string[] _stepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private bool _processing;
    private bool _submitted;
    private int _applicationId;
    private string? _errorMessage;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<bool> _currentJobFlags = [false];

    // Step 3
    private readonly List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        _errorMessage = null;
        _currentStep = step;
    }

    private void PrevStep()
    {
        _errorMessage = null;
        if (_currentStep > 0)
            _currentStep--;
    }

    private async Task NextStep()
    {
        _errorMessage = null;
        _processing = true;
        try
        {
            if (!ValidateCurrentStep())
                return;

            if (_currentStep == 0)
            {
                var valid = await ApplicationService.ValidateEmailAsync(_email);
                if (!valid)
                {
                    _errorMessage = "Please enter a valid email address.";
                    return;
                }
            }

            _currentStep++;
        }
        finally
        {
            _processing = false;
        }
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
                    string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
                {
                    _errorMessage = "All fields are required.";
                    return false;
                }
                break;
            case 1:
                foreach (var entry in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                        entry.StartDate == default)
                    {
                        _errorMessage = "Company, title, and start date are required for each work entry.";
                        return false;
                    }
                }
                break;
            case 2:
                if (_references.Count < 2)
                {
                    _errorMessage = "At least 2 references are required.";
                    return false;
                }
                foreach (var r in _references)
                {
                    if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                        string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
                    {
                        _errorMessage = "All reference fields are required.";
                        return false;
                    }
                }
                break;
            case 3:
                if (string.IsNullOrWhiteSpace(_coverLetter))
                {
                    _errorMessage = "Please write a cover letter.";
                    return false;
                }
                if (_coverLetter.Length > 2000)
                {
                    _errorMessage = "Cover letter must be 2000 characters or fewer.";
                    return false;
                }
                break;
        }
        return true;
    }

    private async Task SubmitApplication()
    {
        _processing = true;
        _errorMessage = null;
        try
        {
            var workEntries = _workEntries.Select((e, i) =>
                new WorkEntry(e.Company, e.Title, e.StartDate, _currentJobFlags[i] ? null : e.EndDate, e.Description))
                .ToList();

            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(
                new PersonalInfo(_fullName, _email, _phone, _address),
                new WorkHistory(workEntries),
                refs,
                _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _processing = false;
        }
    }

    // Mutable models for form binding
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

