@using static sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            var entry = Entries[index];

            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Position @(index + 1)</h6>
                    @if (Entries.Count > 1)
                    {
                        <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                    }
                </div>

                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="entry.Company" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="entry.Title" />
                    </div>
                </div>

                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" @bind="entry.StartDate" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" @bind="entry.EndDate" disabled="@CurrentFlags[index]" />
                    </div>
                    <div class="col-md-4 mb-3 d-flex align-items-end">
                        <div class="form-check">
                            <input type="checkbox" class="form-check-input" id="current-@index"
                                   checked="@CurrentFlags[index]"
                                   @onchange="e => ToggleCurrent(index, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="current-@index">Currently working here</label>
                        </div>
                    </div>
                </div>

                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
                </div>
            </div>
        }

        <button type="button" class="btn btn-outline-primary btn-sm" @onclick="AddEntry">
            + Add Another Position
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public List<bool> CurrentFlags { get; set; } = default!;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        CurrentFlags.Add(false);
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
            CurrentFlags.RemoveAt(index);
        }
    }

    private void ToggleCurrent(int index, bool value)
    {
        CurrentFlags[index] = value;
        if (value)
            Entries[index].EndDate = null;
    }
}

@using static sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title">References</h4>
        <p class="text-muted small">Please provide 2–3 professional references.</p>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            var reference = References[index];

            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Reference @(index + 1)</h6>
                    @if (References.Count > 2)
                    {
                        <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                </div>

                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="reference.Name" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="reference.Relationship" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="reference.Email" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="reference.Phone" />
                    </div>
                </div>
            </div>
        }

        @if (References.Count < 3)
        {
            <button type="button" class="btn btn-outline-primary btn-sm" @onclick="AddReference">
                + Add Reference
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

@using static sv_092670d577f14d7eb52b8573ba448c3b.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h5 class="mb-0">Personal Information</h5>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h5 class="mb-0">Work History</h5>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        @for (int i = 0; i < WorkEntries.Count; i++)
        {
            var entry = WorkEntries[i];
            <div class="@(i > 0 ? "border-top pt-2 mt-2" : "")">
                <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                <span class="text-muted small">
                    @entry.StartDate.ToString("MMM yyyy") –
                    @(CurrentFlags[i] ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </span>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0 mt-1 small">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h5 class="mb-0">References</h5>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        @for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            <div class="@(i > 0 ? "border-top pt-2 mt-2" : "")">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="small text-muted">@r.Email · @r.Phone</span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h5 class="mb-0">Cover Letter</h5>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter] public List<bool> CurrentFlags { get; set; } = default!;
    [Parameter] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
}

