    private Task OnPhoneInput(ChangeEventArgs e) => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    private Task OnAddressInput(ChangeEventArgs e) => AddressChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
}"}

