1. <div class="card">
2.     <div class="card-body">
3.         <h4 class="card-title">Cover Letter</h4>
4.         <div class="mb-2">
5.             <textarea class="form-control" rows="10"
6.                       maxlength="@MaxLength"
7.                       value="@CoverLetter"
8.                       @oninput="OnInput"></textarea>
9.         </div>
10.         <div class="text-end text-muted small">
11.             @(CoverLetter?.Length ?? 0) / @MaxLength characters
12.         </div>
13.     </div>
14. </div>
15. 
16. @code {
17.     [Parameter] public string CoverLetter { get; set; } = "";
18.     [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
19.     [Parameter] public int MaxLength { get; set; } = 2000;
20. 
21.     private async Task OnInput(ChangeEventArgs e)
22.     {
23.         var value = e.Value?.ToString() ?? "";
24.         if (value.Length > MaxLength)
25.             value = value[..MaxLength];
26.         await CoverLetterChanged.InvokeAsync(value);
27.     }
28. }
29.

